sql:
SELECT order_id, product_id, quantity
FROM order_line_items
WHERE lineitem_total > 100;

SELECT order_id, COUNT(*) AS total_work_items
FROM work_items
GROUP BY order_id;

SELECT o.order_id, o.customer_name, o.total_amount, wi.task_type, wi.status
FROM orders o
INNER JOIN work_items wi ON o.order_id = wi.order_id;

SELECT SUM(total_amount) AS TotalRevenue
FROM orders
WHERE order_date BETWEEN '2022-01-01' AND '2022-12-31';

external_knowledge:
- "risen to the zenith of the market" means products that have achieved the highest revenue;
- "order frequencies" refers to the number of orders per product;
- "labor movements" refer to the number of work items associated with each order, representing the labor or operational effort to fulfill the orders;
- "revenue peak" is a metaphorical expression for the highest total revenue;
- May refers to the month of May 2023.
